const EXAMENES_2018 = [
{ex:"2018-A", n:1, area:"PED", tema:"Membrana hialina", q:"Recién nacido por cesárea, con 29 semanas de edad gestacional, presenta marcada dificultad respiratoria. ¿Cuál es la terapia indicada luego de la atención de urgencia?", o:["Surfactante","Corticoide","Óxido nítrico","Vitamina K","Tetraciclina"], c:0, e:"En el prematuro con dificultad respiratoria por déficit de surfactante (enfermedad de membrana hialina), la terapia post-reanimación es el surfactante exógeno; el corticoide se usa antenatal en la madre, no como tratamiento del RN ya nacido."},
{ex:"2018-A", n:2, area:"MED", tema:"Diabetes mellitus 2", q:"En el tratamiento de diabetes mellitus tipo 2, ¿cuál de los siguientes fármacos aumenta la excreción urinaria de glucosa?", o:["Sitagliptina","Metformina","Glimepirida","Pioglitazona","Empagliflozina"], c:4, e:"Los inhibidores de SGLT2 como la empagliflozina bloquean la reabsorción de glucosa en el túbulo proximal, generando glucosuria terapéutica; los demás fármacos actúan por otros mecanismos (incretinas, sensibilización a insulina, secretagogos)."},
{ex:"2018-A", n:3, area:"PED", tema:"Cuerpo extraño en vía aérea", q:"Preescolar de 3 años llega a emergencia por presentar bruscamente violentos paroxismos de tos y marcada dificultad respiratoria. Examen: FR 40x', FC 120x', aleteo nasal, Sat O2 90%, murmullo vesicular disminuido en hemitórax derecho con sibilancias localizadas en la misma zona. ¿Cuál es el diagnóstico probable?", o:["Neumonía viral","Crup espasmódico","Neumotórax","Crisis asmática","Cuerpo extraño"], c:4, e:"El inicio súbito con tos paroxística y hallazgos auscultatorios unilaterales (murmullo disminuido y sibilancias localizadas en una sola zona) es muy sugerente de aspiración de cuerpo extraño, a diferencia del asma que suele ser bilateral."},
{ex:"2018-A", n:4, area:"PED", tema:"Desarrollo psicomotor", q:"¿A qué edad en meses el niño logra hacer una torre con 7 cubos?", o:["24","15","18","12","20"], c:0, e:"El hito de construir una torre de 6-7 cubos se alcanza alrededor de los 24 meses; a los 12 meses el niño apila apenas 2 cubos y a los 18 meses 3-4 cubos."},
{ex:"2018-A", n:5, area:"MED", tema:"Tromboembolia pulmonar", q:"Mujer de 50 años, obesa, hipertensa, con antecedente de cáncer de colon, viaja en bus de Tumbes a Lima; al llegar presenta súbitamente dolor torácico, disnea y síncope. Ingresa con PA 120/60, FC 120x', FR 30x', Sat O2 96%. Con diagnóstico de tromboembolismo pulmonar, ¿cuál es la dosis de enoxaparina que se debe administrar?", o:["1 mg/kg cada 24 horas SC","1 mg/kg cada 12 horas EV","1 mg/kg cada 24 horas EV","1 mg/kg cada 12 horas SC","2 mg/kg cada 12 horas EV"], c:3, e:"La dosis terapéutica estándar de enoxaparina en TEP es 1 mg/kg cada 12 horas por vía subcutánea; las heparinas de bajo peso molecular no se administran por vía endovenosa."},
{ex:"2018-A", n:6, area:"GIN", tema:"Miomatosis uterina", q:"Paciente de 37 años, con antecedente de menometrorragia hace 1 año. Examen pélvico: útero aumentado de tamaño, irregular, firme e indoloro. ¿Cuál es el diagnóstico más probable?", o:["Pólipo endometrial","Endometritis","Hiperplasia endometrial","Miomas uterinos","Cáncer cervical invasor"], c:3, e:"Un útero aumentado de tamaño, irregular (multinodular), firme e indoloro con sangrado anormal crónico es el cuadro clásico de la miomatosis uterina; la endometritis cursaría con dolor y fiebre."},
{ex:"2018-A", n:7, area:"CIR", tema:"Síndrome compartimental", q:"Varón de 28 años, luego de 8 horas de accidente de tránsito, presenta intenso dolor en pierna derecha con incapacidad funcional. Examen: PA 120/80, pulso 90x', pierna derecha con aumento de volumen y edema (+++), ausencia de pulso pedio. Rx: fisura diafisaria en tibia derecha. Ecodoppler: disminución del flujo arterial distal. ¿Cuál es el tratamiento inicial?", o:["Inmovilización del miembro inferior derecho","Colocación de placa y tornillos","Fijación externa","Fasciotomía de pierna derecha","Revascularización de la arteria"], c:3, e:"El edema marcado, dolor intenso y compromiso del flujo arterial distal tras una fractura configuran un síndrome compartimental; el tratamiento urgente es la fasciotomía para evitar necrosis muscular irreversible."},
{ex:"2018-A", n:8, area:"PED", tema:"APGAR", q:"La calificación del APGAR permite identificar ..... del recién nacido.", o:["el desarrollo neurológico","la vitalidad","el desarrollo neuromuscular","la edad gestacional","el grado de dificultad respiratoria"], c:1, e:"El APGAR es una escala clínica que evalúa la vitalidad y adaptación inmediata del RN (frecuencia cardiaca, respiración, tono, reflejos y color), no la edad gestacional ni el desarrollo neurológico."},
{ex:"2018-A", n:9, area:"CB", tema:"Farmacología broncodilatadores", q:"¿Cuál es el mecanismo de acción del bromuro de Ipratropio?", o:["Bloquea los receptores Cis_LT1","Activa los receptores adrenérgicos beta 2","Antagoniza los receptores muscarínicos","Disminuye el número de células inflamatorias","Inhibe la fosfodiesterasa del músculo liso"], c:2, e:"El ipratropio es un anticolinérgico que antagoniza los receptores muscarínicos bronquiales, produciendo broncodilatación; los agonistas beta2 son los que activan receptores adrenérgicos beta 2."},
{ex:"2018-A", n:10, area:"GIN", tema:"Infertilidad tubárica", q:"Paciente de 28 años, acude por dos años de intento reproductivo sin éxito. Antecedente de múltiples parejas sexuales. Examen: sin alteraciones. Histerosalpingografía: obstrucción de trompas. ¿Cuál es la causa más probable de infertilidad?", o:["Factor adherencial","Enfermedad pélvica inflamatoria","Miomatosis uterina","Malformaciones uterinas","Hiperplasia endometrial"], c:1, e:"El antecedente de múltiples parejas sexuales sugiere ITS previas que evolucionan a enfermedad pélvica inflamatoria, causa más frecuente de obstrucción tubárica e infertilidad de factor tubárico."},
{ex:"2018-A", n:11, area:"PED", tema:"Estenosis hipertrófica de píloro", q:"Recién nacido de 4 semanas con vómitos en 'proyectil'; le diagnostican estenosis hipertrófica del píloro. ¿Cuál es el tratamiento quirúrgico de elección?", o:["Piloromiotomía laparoscópica","Esofagostomía","Gastroduodeno anastomosis","Gastrectomía distal","Gastrostomía"], c:0, e:"El tratamiento definitivo de la estenosis hipertrófica del píloro es la piloromiotomía (técnica de Fredet-Ramstedt), hoy realizada preferentemente por vía laparoscópica."},
{ex:"2018-A", n:12, area:"MED", tema:"Fibrilación auricular", q:"Varón de 48 años hipertenso, ingresa a emergencia por palpitaciones, síncope y disnea. Examen: despierto, taquipneico, PA 110/70, FC 140x', FR 22x', Sat O2 97%. EKG: taquiarritmia de complejos angostos irregulares compatibles con fibrilación auricular. ¿Cuál es el tratamiento de elección para el control de frecuencia cardiaca?", o:["Lidocaína","Adenosina","Labetalol","Propafenona","Digoxina"], c:2, e:"Para el control agudo de frecuencia en FA sintomática se prefieren betabloqueadores EV (como labetalol) o calcioantagonistas no dihidropiridínicos; la digoxina es de segunda línea, y adenosina/lidocaína no son fármacos de control de frecuencia en FA."},
{ex:"2018-A", n:13, area:"CIR", tema:"Otitis media complicada", q:"Varón de 40 años, con dolor en oído izquierdo de moderada intensidad y fiebre. Recibe tratamiento con antiinflamatorios y antibióticos. Seis semanas después aparece otorrea e hipoacusia. ¿Cuál es la complicación más frecuente?", o:["Meningitis","Nistagmus persistente","Sinusitis","Rinorrea crónica","Parálisis del V par"], c:0, e:"La otitis media que evoluciona a otorrea crónica e hipoacusia puede complicarse por diseminación intracraneal; entre las opciones, la meningitis es la complicación temida que corresponde a la clave oficial."},
{ex:"2018-A", n:14, area:"SP", tema:"Redes Integradas de Salud", q:"La siguiente definición: 'una red de organizaciones que presta, o hace los arreglos para prestar, servicios de salud equitativos e integrales a una población definida, y está dispuesta a rendir cuentas por sus resultados clínicos y económicos y por el estado de salud de la población a la que sirve', corresponde a:", o:["Redes Integradas de Servicios de Salud","Modelo Mixto de Atención de Salud","Sistema de Integración Horizontal","Modelo de Atención Integral de Salud","Asociación Público Privada de Salud"], c:0, e:"Esta es la definición clásica (OPS) de Redes Integradas de Servicios de Salud (RISS), un modelo organizativo que busca continuidad y responsabilidad compartida en la atención de una población."},
{ex:"2018-A", n:15, area:"PED", tema:"Vacuna DPT", q:"¿Cuáles son los efectos adversos sistémicos más frecuentes, luego de vacunar a un niño con DPT?", o:["Irritabilidad, fiebre (38°C), somnolencia","Vómito, edema, dolor","Diaforesis, sueño, vómito","Dolor, vómito, convulsiones","Convulsiones, llanto excesivo"], c:0, e:"Los efectos sistémicos más comunes de la DPT (componente pertussis de células enteras) son fiebre moderada, irritabilidad y somnolencia; las convulsiones y el llanto persistente son reacciones raras y graves."},
{ex:"2018-A", n:16, area:"SP", tema:"Norma técnica TBC", q:"De acuerdo a la norma técnica de tuberculosis, al paciente al que se le realiza una o más baciloscopías de esputo corresponde a un sintomático respiratorio...", o:["descartado","sospechoso","examinado","identificado","detectado"], c:2, e:"Según la norma técnica de TBC del MINSA, el sintomático respiratorio al que ya se le tomó la muestra de baciloscopía se clasifica como 'examinado', distinto del 'identificado' (captado) o 'sospechoso'."},
{ex:"2018-A", n:17, area:"MED", tema:"Nitrofurantoína", q:"Mujer de 50 años hipertensa, hipotiroidea, con enfermedad renal crónica estadio III y con antecedente de infecciones urinarias a repetición, desarrolla neuropatía periférica. ¿Cuál es el fármaco más asociado a este efecto adverso?", o:["Tiamazol","Nitrofurantoína","Enalapril","Furosemida","Levotiroxina"], c:1, e:"La nitrofurantoína, usada frecuentemente en ITU de repetición, se asocia a neuropatía periférica, riesgo que aumenta notablemente en pacientes con ERC por acumulación del fármaco y sus metabolitos."},
{ex:"2018-A", n:18, area:"MED", tema:"Crisis de ausencia", q:"¿Cuál es el tratamiento de elección en pacientes con crisis de ausencia?", o:["Ácido valproico","Gabapentina","Fenitoína","Carbamazepina","Fenobarbital"], c:0, e:"El ácido valproico (junto con la etosuximida) es de elección en las crisis de ausencia; la carbamazepina y la fenitoína pueden incluso exacerbarlas."},
{ex:"2018-A", n:19, area:"CIR", tema:"Fracturas/inmovilización", q:"Varón, con fractura en tercio medio de tibia derecha sin desplazamiento. Presenta marcada inflamación y edema de la extremidad lesionada. ¿Cuál es el periodo ideal en horas para colocar el aparato de yeso?", o:["10-18","72-96","01-09","24-72","19-23"], c:3, e:"Se espera a que ceda el edema inicial (24-72 horas) antes de colocar un yeso circular cerrado, para evitar compresión progresiva y síndrome compartimental secundario."},
{ex:"2018-A", n:20, area:"GIN", tema:"Manejo del alumbramiento", q:"¿Cuál de los siguientes fármacos puede ser usado como uterotónico en el manejo del alumbramiento?", o:["Terbutalina","Atosibán","Progesterona","Oxitocina","Levonorgestrel"], c:3, e:"La oxitocina es el uterotónico de primera línea en el manejo activo del alumbramiento, reduciendo el riesgo de hemorragia postparto por atonía uterina."},
{ex:"2018-A", n:21, area:"PED", tema:"Exantema súbito", q:"Lactante de 11 meses, presenta durante 3 días fiebre de 39°C, que cede espontáneamente, presentando luego erupción máculo-papular rosada no pruriginosa en tronco, que se extiende a cara y extremidades. ¿Cuál es el diagnóstico?", o:["Escarlatina","Roséola","Sarampión","Eritema infeccioso","Rubéola"], c:1, e:"El exantema súbito (roséola, por herpesvirus 6) se caracteriza por fiebre alta de 3-5 días que cede bruscamente, apareciendo luego el exantema en tronco, típico de lactantes con buen estado general."},
{ex:"2018-A", n:22, area:"CIR", tema:"Trauma uretral", q:"Varón de 30 años, presenta caída a 'horcajada', llega a emergencia con hematuria franca, incapacidad para orinar. Examen: hematoma perineal y sangre en el meato urinario. ¿Cuál es la estructura lesionada?", o:["Riñón","Vejiga","Próstata","Uretra","Uréter"], c:3, e:"La caída a horcajadas es el mecanismo clásico de lesión de la uretra bulbar; sangre en meato, hematoma perineal y retención urinaria son signos característicos que contraindican el sondaje vesical ciego."},
{ex:"2018-A", n:23, area:"CIR", tema:"Quemadura ocular química", q:"Niño de 12 años que sufre quemadura oftálmica con lejía, se diagnostica queratitis traumática. ¿Cuál es el tratamiento inicial?", o:["Corticoterapia sistémica","Antiinflamatorios sistémicos","Oclusión de ojo afectado","Anestésicos locales","Lavado y antibioticoterapia"], c:4, e:"Ante una quemadura química ocular por álcali, la prioridad inmediata es el lavado abundante para eliminar el agente cáustico, seguido de antibioticoterapia tópica para prevenir sobreinfección."},
{ex:"2018-A", n:24, area:"MED", tema:"IAM tipo 2", q:"Varón de 52 años, diabético y con enfermedad renal crónica en hemodiálisis, presenta hemorragia digestiva alta, hipotenso y taquicárdico. Hb: 5 g/dl. Evoluciona con dolor precordial opresivo y disnea. EKG: cambios compatibles con síndrome coronario agudo. Según la clasificación universal de infarto de miocardio, ¿a qué tipo corresponde?", o:["2","3","4","1","5"], c:0, e:"El IAM tipo 2 ocurre por desbalance entre aporte y demanda de oxígeno miocárdico (aquí por anemia severa e hipotensión secundarias a hemorragia digestiva), sin rotura de placa como en el tipo 1."},
{ex:"2018-A", n:25, area:"CIR", tema:"Anestesia regional", q:"¿Cómo se denomina el tipo de anestesia neuroaxial de aplicación extradural en la periferia?", o:["Sedación","Endovenosa","Subdural","General","Regional"], c:4, e:"Los bloqueos aplicados en nervios periféricos, fuera del neuroeje central, se agrupan dentro de la anestesia regional, distinta de la anestesia general o la sedación sistémica."},
{ex:"2018-A", n:26, area:"SP", tema:"Atención integral del RN", q:"¿Cuál de las siguientes alternativas corresponde a la Atención Integral de Salud del Recién Nacido?", o:["Visita familiar integral para nacidos de bajo peso","Atención a prioridades sanitarias IRA","Evaluación músculo esquelética","Prevención de enfermedades prevalentes","Intervenciones educativas a los padres sobre higiene"], c:0, e:"Dentro del paquete de Atención Integral de Salud del RN según el MINSA, se contempla la visita familiar integral prioritaria para los recién nacidos de bajo peso, por su mayor riesgo de morbimortalidad."},
{ex:"2018-A", n:27, area:"GIN", tema:"Profilaxis anti-D", q:"Gestante O Rh (-) con pareja O Rh (+), no sensibilizada. ¿Entre qué edad gestacional en semanas debe recibir la inmunoglobulina anti D?", o:["34 y 38","22 y 26","28 y 32","36 y 38","18 y 22"], c:2, e:"En la gestante Rh negativa no sensibilizada se administra profilaxis con inmunoglobulina anti-D entre las 28 y 32 semanas, con una segunda dosis posparto si el RN resulta Rh positivo."},
{ex:"2018-A", n:28, area:"SP", tema:"Diseño de estudios", q:"¿Cuál de los siguientes estudios epidemiológicos se aplica para conocer la prevalencia de una enfermedad en la población?", o:["Caso control","Cohorte","Transversal","Correlacional","Experimental"], c:2, e:"El estudio transversal mide exposición y desenlace en un mismo momento en el tiempo, siendo el diseño adecuado para estimar la prevalencia de una enfermedad en la población."},
{ex:"2018-A", n:29, area:"GIN", tema:"Embarazo postérmino", q:"Primigesta de 42 semanas acude por contracciones uterinas esporádicas y pérdida del tapón mucoso, sin signos de alarma. Examen: PA 90/60, altura uterina 33 cm, longitudinal cefálico derecho, latidos fetales 142x', test no estresante reactivo, al tacto vaginal sin cambios cervicales y pelvis ginecoide. ¿Cuál es la conducta a seguir?", o:["Observación hospitalizada","Inducción de trabajo de parto","Parto por cesárea","Observación ambulatoria","Ruptura de membranas"], c:1, e:"El embarazo en o más allá de las 41-42 semanas (postérmino) sin contraindicaciones para parto vaginal amerita la inducción del trabajo de parto, para evitar los riesgos de insuficiencia placentaria y macrosomía."},
{ex:"2018-A", n:30, area:"PED", tema:"Resfrío común", q:"Lactante de 6 meses que inicia con rinorrea acuosa, estornudos, fiebre, hiporexia, luego tos y ronquera. Examen: FR 32x', FC 120x', eutrófico, rinorrea transparente, orofaringe congestiva, membranas timpánicas con eritema circular y respiración ruda bilateral. ¿Cuál es el diagnóstico?", o:["Sinusitis","Resfrío común","Faringitis aguda","Bronquitis","Otitis media aguda"], c:1, e:"Un cuadro catarral leve con rinorrea, congestión faríngea y eritema timpánico leve (sin abombamiento ni otalgia franca) es compatible con resfrío común de etiología viral, no con otitis media aguda."},
{ex:"2018-A", n:31, area:"CB", tema:"Metaplasia escamosa bronquial", q:"Varón de 50 años, con baja de peso y tos productiva. Antecedente: consumo de cigarrillos desde los 15 años. Luego de evaluación y estudios, se diagnostica carcinoma epidermoide pulmonar en estadios iniciales del cáncer. ¿A qué tipo de epitelio se transforma el pseudoestratificado cilíndrico?", o:["Estratificado escamoso","Simple cilíndrico","Simple cúbico","Simple granular","Poliestratificado mucinoso"], c:0, e:"El humo del tabaco induce metaplasia escamosa: el epitelio respiratorio pseudoestratificado ciliado se transforma en epitelio estratificado escamoso, lesión precursora del carcinoma epidermoide."},
{ex:"2018-A", n:32, area:"CB", tema:"Farmacología del asma", q:"¿Cuál es el fármaco inhibidor de la fosfodiesterasa que se emplea en el tratamiento del asma?", o:["Budesonida","Montelukast","Teofilina","Tiotropio","Salmeterol"], c:2, e:"La teofilina actúa inhibiendo la fosfodiesterasa, con lo que aumenta el AMPc intracelular y produce broncodilatación; los demás fármacos listados actúan por mecanismos distintos (corticoide, antileucotrieno, anticolinérgico, agonista beta2)."},
{ex:"2018-A", n:33, area:"PED", tema:"Infección urinaria en lactante", q:"Lactante mujer de 18 meses, con episodios de diarrea a repetición, hiporexia y pobre ganancia pondoestatural. Es traída a emergencia con fiebre alta y vómitos alimentarios. Examen: adelgazada, pálida, signos de deshidratación leve, abdomen excavado. Laboratorio: reacción inflamatoria negativa. ¿En qué diagnóstico sospecha?", o:["Intolerancia a la lactosa","Intoxicación alimentaria","Gastritis","Infección urinaria","Diarrea bacteriana"], c:3, e:"En lactantes la ITU puede manifestarse de forma atípica con diarrea crónica, hiporexia y falla de medro; la reacción inflamatoria negativa en heces descarta causa entérica invasiva y orienta a foco urinario."},
{ex:"2018-A", n:34, area:"CB", tema:"Lactógeno placentario", q:"¿Cuál es la principal acción del lactógeno placentario humano durante el embarazo?", o:["Actividad autoinmune","Relajar el músculo liso","Antagonizar la acción de la insulina","Mantener el cuerpo lúteo","Disminuir el flujo sanguíneo del útero"], c:2, e:"El lactógeno placentario humano genera resistencia a la insulina materna, favoreciendo la disponibilidad de glucosa y ácidos grasos para el feto; esta acción explica en parte el riesgo de diabetes gestacional."},
{ex:"2018-A", n:35, area:"MED", tema:"Colitis pseudomembranosa", q:"Varón de 22 años, desde hace 3 días presenta deposiciones líquidas sanguinolentas 2 a 3 veces/día, con vómitos, fiebre y dolor abdominal tipo cólico. Antecedente de tratamiento antimicrobiano hace 1 semana. Examen: T° 38°C, FP 98x', deshidratado; abdomen con ligera distensión y aumento de ruidos hidroaéreos. ¿Cuál es el agente causal más frecuente?", o:["Clostridium difficile","Rotavirus","Campylobacter jejuni","Vibrion cholerae","Shigella sp"], c:0, e:"La diarrea sanguinolenta que aparece tras el uso reciente de antibióticos es característica de colitis por Clostridium difficile, secundaria a la disrupción de la flora colónica normal."},
{ex:"2018-A", n:36, area:"GIN", tema:"HTA en el embarazo", q:"¿Cuál de los siguientes fármacos está contraindicado en la gestante hipertensa?", o:["Inhibidores de enzima de conversión de angiotensina II","Simpaticolíticos con acción central","Antagonistas alfa selectivos","Vasodilatadores directos","Antagonistas de los canales de calcio"], c:0, e:"Los IECA (y ARA-II) están contraindicados en el embarazo por su teratogenicidad renal fetal (oligohidramnios, disgenesia renal); la alfametildopa, los calcioantagonistas y los vasodilatadores directos son opciones seguras."},
{ex:"2018-A", n:37, area:"MED", tema:"Síndrome de Fanconi", q:"Varón de 60 años, acude a consulta por dolor óseo, debilidad muscular y fatiga. Bioquímica sanguínea: hipofosfatemia, normocalcemia, acidosis metabólica hiperclorémica, hipouricemia e hipokalemia. Dipstick urinario: glucosa (+), proteinuria (+). ¿En qué zona de la nefrona se encuentra el defecto?", o:["Túbulo contorneado proximal","Asa descendente de Henle","Túbulo colector","Asa ascendente de Henle","Túbulo distal"], c:0, e:"La combinación de glucosuria, fosfaturia, aminoaciduria y acidosis metabólica hiperclorémica corresponde al síndrome de Fanconi, por disfunción global de la reabsorción en el túbulo contorneado proximal."},
{ex:"2018-A", n:38, area:"GIN", tema:"Transmisión vertical de VIH", q:"¿Cuál de las siguientes condiciones aumenta el riesgo de transmisión vertical de VIH?", o:["Ruptura de membranas mayor de 4 horas","Carga viral indetectable","Pinzamiento del cordón umbilical sin ordeñar","Tratamiento antirretroviral","Profilaxis antirretroviral antes del parto"], c:0, e:"La ruptura prolongada de membranas (mayor de 4 horas) aumenta el tiempo de exposición fetal a secreciones maternas infectadas, elevando el riesgo de transmisión vertical del VIH."},
{ex:"2018-A", n:39, area:"GIN", tema:"Anticoncepción y lactancia", q:"¿Cuál de los siguientes métodos anticonceptivos está contraindicado durante la lactancia materna?", o:["Dispositivo intrauterino","Método de barrera","Progestágeno inyectable","Píldoras de solo progestágenos","Anticonceptivos orales combinados"], c:4, e:"Los anticonceptivos orales combinados están contraindicados durante la lactancia porque el componente estrogénico reduce la producción de leche; los métodos de solo progestágeno son seguros en esta etapa."},
{ex:"2018-A", n:40, area:"CIR", tema:"Complicaciones del yeso", q:"La erosión cutánea por el aparato de yeso es una complicación que puede ser devastadora. ¿Por qué se ocasiona?", o:["Acojinamiento insuficiente sobre prominencia ósea","Colocación de la férula en muy corto tiempo","Falta de cubierta con calcetín de tela","Férula de gran espesor","Falta de cubierta con manga"], c:0, e:"La erosión cutánea bajo el yeso ocurre principalmente por acojinamiento insuficiente sobre las prominencias óseas, que concentran la presión y comprometen la perfusión local de la piel."},
{ex:"2018-A", n:41, area:"PED", tema:"Deshidratación e hiponatremia", q:"Lactante de 8 meses, presenta desde hace 2 días diarrea, vómitos e hiporexia. Examen: letárgico, pálido, extremidades distales frías, abdomen distendido, taquicárdico. ¿Qué alteración electrolítica explica el compromiso del sensorio?", o:["Hiponatremia","Hiperkalemia","Hipernatremia","Hipocalcemia","Hipokalemia"], c:0, e:"En la deshidratación por pérdidas gastrointestinales con reposición inadecuada, la hiponatremia (por edema cerebral osmótico) es la causa más frecuente de compromiso del sensorio y letargia."},
{ex:"2018-A", n:42, area:"MED", tema:"TBC en VIH avanzado", q:"¿Cuál es el patrón radiológico más frecuente de tuberculosis pulmonar en pacientes VIH, con linfocitos CD4 < 200/µl?", o:["Linfoadenopatía intratorácica","Infiltrado intersticial difuso","Cavitaria en ápices","Neumónico basal","Derrame pleural"], c:1, e:"En la inmunosupresión avanzada (CD4<200) la TBC suele presentarse de forma atípica, con infiltrado intersticial difuso o patrón miliar y adenopatías, en vez del clásico patrón cavitario apical del inmunocompetente."},
{ex:"2018-A", n:43, area:"CIR", tema:"Lesión ligamentaria de rodilla", q:"Varón de 30 años, sufre accidente de tránsito. Examen: rodilla derecha tumefacta, con signos de flogosis y muy dolorosa a la palpación, movimiento lateral y medial de tibia. ¿Cuál es el probable diagnóstico?", o:["Luxación de rótula","Ruptura de ligamentos lateral y medial","Fractura de tibia y peroné","Ruptura del cuadriceps","Fractura de tibia y fémur"], c:1, e:"La inestabilidad en varo y valgo (movimiento lateral y medial anormal de la tibia) traduce lesión de los ligamentos colaterales lateral y medial de la rodilla."},
{ex:"2018-A", n:44, area:"CIR", tema:"Ruptura del tendón de Aquiles", q:"Durante los ejercicios físicos bruscos, frecuentemente se produce la ruptura del tendón de Aquiles. ¿Cuál es la causa más probable de esta lesión?", o:["Contusión directa sobre el tendón","Cambios bruscos de dirección","Excesivos ejercicios anteriores","Poco calentamiento previo de músculos","Ejercitar las mismas rutinas"], c:1, e:"Los cambios bruscos de dirección generan una sobrecarga excéntrica súbita sobre el tendón de Aquiles, mecanismo más frecuentemente implicado en su ruptura durante el deporte."},
{ex:"2018-A", n:45, area:"MED", tema:"Anemia hemolítica", q:"Mujer de 28 años, hace 15 días presenta cansancio, disnea a medianos esfuerzos y artralgias. Examen: palidez de piel y mucosas, ictericia, no adenopatías periféricas, abdomen: hígado y bazo palpables. Laboratorio: Hb 8.5 g/dl, BT 4.5, BI 3.8 mg/dl, reticulocitos 3%, DHL 1200 mg/dl. ¿Cuál es el tipo de anemia?", o:["Hemolítica","Deficiencia de B12","Mielodisplásica","Ferropénica","Deficiencia de ácido fólico"], c:0, e:"Anemia con ictericia, esplenomegalia, hiperbilirrubinemia indirecta, reticulocitosis y DHL elevada configuran el patrón clásico de anemia hemolítica."},
{ex:"2018-A", n:46, area:"SP", tema:"Determinantes sociales de la salud", q:"Dentro de los Determinantes Sociales de la Salud, ¿cuáles son Determinantes Intermediarios?", o:["Cohesión social, conducta, factores biológicos","Ocupación, educación, posición social","Contexto político, gobernanza, atención sanitaria","Normas y valores culturales, posición social","Circunstancias materiales, género, raza"], c:0, e:"Los determinantes intermediarios incluyen las circunstancias materiales, los factores conductuales y biológicos, y la cohesión social; los determinantes estructurales corresponden a la posición socioeconómica y el contexto político."},
{ex:"2018-A", n:47, area:"PED", tema:"Migraña", q:"Adolescente de 13 años, presenta en forma recurrente cefalea pulsátil, focalizada en región frontal, de moderada intensidad y en incremento, asociada a náuseas, vómitos y fotofobia. Antecedente de madre con cuadro similar. ¿Cuál es el diagnóstico probable?", o:["Depresión","Ametropía","Tumor cerebral","Migraña","Aneurisma"], c:3, e:"Cefalea pulsátil recurrente con náuseas, vómitos y fotofobia, más el antecedente familiar materno, es el cuadro típico de migraña, entidad con fuerte componente hereditario."},
{ex:"2018-A", n:48, area:"PED", tema:"Sepsis neonatal precoz", q:"¿Cuál es el agente infeccioso más frecuente en sepsis neonatal precoz?", o:["Staphylococcus aureus","Escherichia coli","Enterococcus faecalis","Chlamydia trachomatis","Pseudomona sp"], c:1, e:"En la sepsis neonatal precoz (menor de 72 horas), Escherichia coli y Streptococcus agalactiae son los agentes más frecuentes de transmisión vertical."},
{ex:"2018-A", n:49, area:"PED", tema:"Inmunodeficiencia y vacunas vivas", q:"Lactante de 11 meses con antecedente de dos episodios de neumonía bacteriana y uno de otitis media aguda; hermano fallecido a los 18 meses por sepsis. ¿Cuál de las siguientes vacunas está contraindicada?", o:["Antineumocócica","Polio inyectable","Influenza","Vacuna triple vírica","Pentavalente"], c:3, e:"Las infecciones recurrentes graves y la muerte de un hermano por sepsis sugieren una inmunodeficiencia primaria; en estos pacientes las vacunas de virus vivos atenuados, como la triple vírica, están contraindicadas por riesgo de enfermedad diseminada."},
{ex:"2018-A", n:50, area:"GIN", tema:"Chancroide", q:"Mujer de 23 años, acude por presentar lesiones genitales hace 10 días. Examen: adenopatía inguinal bilateral y dolorosa, lesiones ulcerativas profundas, con márgenes irregulares y bordes excavados. ¿Cuál es el diagnóstico más probable?", o:["Granuloma inguinal","Chancroide","Sífilis","Herpes genital","Donovanosis"], c:1, e:"Las úlceras genitales dolorosas, de bordes irregulares y excavados, con adenopatía inguinal dolorosa ('bubón'), son características del chancroide (Haemophilus ducreyi), a diferencia del chancro sifilítico que es indoloro."},
{ex:"2018-A", n:51, area:"MED", tema:"H. pylori y cáncer gástrico", q:"Mujer de 40 años, con molestias digestivas leves, se indica endoscopía gástrica. ¿Qué se espera encontrar en relación a la prevención del cáncer gástrico?", o:["Pólipos adenomatosos","Úlcera duodenal","Helicobacter pylori","Gastritis","Úlcera gástrica"], c:2, e:"La detección y erradicación de Helicobacter pylori es la principal estrategia de prevención del cáncer gástrico, al ser el factor de riesgo modificable más importante para esta neoplasia."},
{ex:"2018-A", n:52, area:"GIN", tema:"Miomas uterinos", q:"¿Cuál es el mioma uterino que clínicamente produce abundante sangrado vaginal acompañado de coágulos?", o:["Submucoso","Mixto","Intramural","Subseroso","Endometrial"], c:0, e:"El mioma submucoso, por su relación directa con la cavidad endometrial, es el que produce sangrado uterino anormal más abundante, incluso con coágulos, a diferencia del subseroso que suele ser asintomático."},
{ex:"2018-A", n:53, area:"CIR", tema:"Coledocolitiasis", q:"Mujer de 40 años, desde hace tres días con ictericia leve, no fiebre, dolor tipo cólico en hipocondrio derecho. Antecedente de colecistitis crónica. Examen: ictericia de piel y escleras. Abdomen: distendido y dolor a la palpación profunda en hipocondrio derecho. ¿Cuál es el examen indicado para su diagnóstico?", o:["Tomografía abdominal","Ecografía endoscópica","Colangiografía endoscópica","Colecistografía endovenosa","Ecografía abdominal"], c:2, e:"Ante la sospecha de coledocolitiasis con ictericia y dolor cólico, la colangiopancreatografía retrógrada endoscópica permite tanto el diagnóstico como el tratamiento (extracción del cálculo) en el mismo procedimiento."},
{ex:"2018-A", n:54, area:"MED", tema:"Hiponatremia hipovolémica", q:"¿Cuál es la causa de la hiponatremia hipovolémica con sodio urinario mayor de 20 mEq/L?", o:["Diuresis osmótica","Insuficiencia renal aguda","Insuficiencia renal crónica","Deficiencia de glucocorticoides","Pancreatitis aguda"], c:0, e:"La diuresis osmótica (por ejemplo, por glucosuria o manitol) genera pérdida renal de sodio con hiponatremia hipovolémica y sodio urinario elevado (>20 mEq/L), a diferencia de las pérdidas extrarrenales donde el sodio urinario está bajo."},
{ex:"2018-A", n:55, area:"GIN", tema:"Contraindicaciones de tocólisis", q:"Gestante de 31 semanas, ingresa a emergencia por presentar desde hace 8 horas contracciones uterinas de regular intensidad y frecuencia. ¿En qué caso está contraindicado el uso de tocolíticos?", o:["Placenta previa","Corioamnionitis","Dilatación cervical de 1 cm","Ruptura prematura de membranas","Restricción del crecimiento fetal"], c:1, e:"La corioamnionitis contraindica la tocólisis, ya que prolongar el embarazo en presencia de infección intraamniótica aumenta el riesgo de sepsis materna y neonatal; en este caso se prefiere finalizar la gestación."},
{ex:"2018-A", n:56, area:"MED", tema:"Cáncer de pulmón microcítico", q:"Varón de 75 años, consulta por pérdida de peso, tos con expectoración hemoptoica y cefalea global persistente. Sin antecedentes. Examen: adelgazado, pálido, polipneico, pulmones normales. Rx de tórax: masa parahiliar derecha. Tomografía cerebral: imágenes compatibles con metástasis. ¿Cuál es el tipo de cáncer más frecuente?", o:["Adenocarcinoma","Macrocítico de pulmón","Epidermoide","Microcítico de pulmón","Carcinoide bronquial"], c:3, e:"El carcinoma microcítico (células pequeñas) de pulmón, típicamente de localización central/hiliar en fumadores, es el que con mayor frecuencia y precocidad produce metástasis cerebrales al momento del diagnóstico."},
{ex:"2018-A", n:57, area:"PED", tema:"Esquema de vacunación DPT", q:"¿A qué edad en años se administra el segundo refuerzo de la vacuna DPT?", o:["10","4","6","5","3"], c:1, e:"Según el esquema nacional de vacunación, el segundo refuerzo de DPT se administra a los 4 años de edad, tras el primer refuerzo aplicado alrededor de los 18 meses."},
{ex:"2018-A", n:58, area:"CIR", tema:"Fisura anal crónica", q:"Varón de 26 años, desde hace 2 meses diagnosticado de fisura anal no complicada, con tratamiento de ablandadores de heces. La sintomatología dolorosa continúa. ¿Qué tratamiento le recomendaría?", o:["Esfinterotomía lateral interna","Esfinterotomía lateral externa","Anestésicos locales","Infiltración con toxina botulínica","Fisurotomía"], c:0, e:"Ante el fracaso del manejo médico conservador (ablandadores, higiene) en la fisura anal crónica, la esfinterotomía lateral interna es el tratamiento quirúrgico de elección por su alta tasa de curación."},
{ex:"2018-A", n:59, area:"PED", tema:"Conjuntivitis gonocócica neonatal", q:"Recién nacido, con inyección conjuntival y secreción. En el frotis se evidencia diplococos gram negativos. ¿Cuál es el tratamiento de elección?", o:["Cotrimoxazol","Cloranfenicol","Ceftriaxona","Eritromicina","Tetraciclina"], c:2, e:"Los diplococos gram negativos en el frotis conjuntival del RN confirman conjuntivitis gonocócica; el tratamiento de elección es la ceftriaxona, dada la alta tasa de resistencia a otros antibióticos."},
{ex:"2018-A", n:60, area:"GIN", tema:"Tricomoniasis", q:"Paciente de 17 años, con flujo vaginal amarillento, mal olor, asociado a prurito vulvar y vaginal. Especuloscopía: cuello en fresa. ¿Cuál es el tratamiento más adecuado?", o:["Metronidazol","Fluconazol","Azitromicina","Cefixima","Terconazol"], c:0, e:"El flujo amarillento maloliente con prurito y el 'cuello en fresa' (cervicitis punteada) son característicos de tricomoniasis vaginal; el tratamiento de elección es el metronidazol, incluyendo a la pareja sexual."},
{ex:"2018-A", n:61, area:"SP", tema:"Abogacía en salud", q:"La siguiente definición: 'Estrategia de la promoción que combina acciones individuales y sociales destinadas a superar resistencias, prejuicios y controversias; así como a conseguir compromisos y apoyo para las políticas de salud, aceptación social y apoyo de los sistemas para un determinado objetivo o programa de salud'. Corresponde a:", o:["Intersectorialidad","Abogacía","Participación","Interculturalidad","Concertación"], c:1, e:"Esta definición corresponde a la abogacía en salud, estrategia de la promoción de la salud orientada a lograr apoyo político y social para un objetivo sanitario determinado."},
{ex:"2018-A", n:62, area:"GIN", tema:"Sangrado postmenopáusico", q:"Paciente de 60 años, obesa, nulípara, acude refiriendo sangrado vaginal de tres meses de evolución, niega antecedentes familiares de importancia. Examen: sin alteraciones. Papanicolaou negativo. ¿Cuál es el estudio más adecuado?", o:["Ecografía transvaginal","Resonancia magnética","Colposcopía","Histerosonografía","Tomografía"], c:0, e:"Todo sangrado postmenopáusico obliga a descartar patología endometrial; el primer estudio es la ecografía transvaginal para medir el grosor endometrial, sobre todo en esta paciente con factores de riesgo (obesidad, nuliparidad)."},
{ex:"2018-A", n:63, area:"CB", tema:"Fisiología respiratoria", q:"¿Cuál es la presión de oxígeno en mmHg a nivel del capilar pulmonar, después de pasar por el alveolo, en un individuo sano?", o:["100","80","140","60","120"], c:0, e:"La PO2 arterial normal, tras el intercambio gaseoso alveolo-capilar, es aproximadamente 100 mmHg en un individuo sano a nivel del mar."},
{ex:"2018-A", n:64, area:"GIN", tema:"Bacteriuria asintomática en embarazo", q:"¿Cuál es el riesgo en una gestante que, en control prenatal, se diagnostica bacteriuria asintomática y no recibe tratamiento?", o:["Salpingitis","Uretritis","Cistitis","Pielonefritis","Trigonitis"], c:3, e:"La bacteriuria asintomática no tratada en la gestante progresa con frecuencia a pielonefritis aguda, por los cambios fisiológicos del embarazo que favorecen el ascenso bacteriano; por ello se indica tratamiento aunque sea asintomática."},
{ex:"2018-A", n:65, area:"CB", tema:"Respuesta neuroendocrina al shock", q:"¿Cuál es la respuesta neuroendocrina hallada en shock?", o:["Descenso del estímulo adrenérgico","Inhibición de liberación del péptido natriurético cerebral","Menor secreción pancreática de glucagón","Disminución de la liberación de renina","Mayor liberación de ACTH"], c:4, e:"El shock activa el eje hipotálamo-hipófisis-adrenal como respuesta al estrés, aumentando la liberación de ACTH y cortisol, junto con mayor descarga adrenérgica y activación del sistema renina-angiotensina."},
{ex:"2018-A", n:66, area:"SP", tema:"PEAS - niveles de atención", q:"Dentro del Plan Esencial de Aseguramiento en Salud, ¿cuál de las siguientes condiciones en su nivel resolutivo corresponde al Tercer Nivel de Atención?", o:["SIDA","Malaria","Anemia nutricional","Vulvovaginitis","Absceso cutáneo"], c:0, e:"El manejo especializado del SIDA (con sus complicaciones e infecciones oportunistas) requiere la capacidad resolutiva del tercer nivel de atención, a diferencia de patologías más simples resueltas en el primer nivel."},
{ex:"2018-A", n:67, area:"MED", tema:"Intoxicación por cocaína", q:"Adolescente de 15 años, llega a emergencia presentando agitación psicomotriz, alucinaciones visuales. Examen: FC 120x', T° 38.5°C, PA 160/100, piel sudorosa, pupilas dilatadas. ¿Cuál es el tóxico causal?", o:["Benzodiazepina","Órganofosforado","Alcohol","Cocaína","Heroína"], c:3, e:"Agitación, alucinaciones, hipertermia, hipertensión, taquicardia, diaforesis y midriasis conforman un síndrome simpaticomimético típico de la intoxicación por cocaína."},
{ex:"2018-A", n:68, area:"PED", tema:"Reanimación neonatal con meconio", q:"Recién nacido post-término, cesárea por sufrimiento fetal, teñido de meconio. Examen: deprimido, sin esfuerzo respiratorio, bradicárdico, cianótico. ¿Cuál es la conducta a seguir?", o:["Secado enérgico","Oxígeno en cánula binasal","Estimulación táctil","Intubación endotraqueal y aspiración","Óxido nítrico inhalado"], c:3, e:"En el RN teñido de meconio que nace deprimido (sin esfuerzo respiratorio, bradicárdico), se indica intubación endotraqueal con aspiración directa de la vía aérea antes de iniciar la ventilación con presión positiva."},
{ex:"2018-A", n:69, area:"MED", tema:"Prostatitis/ITU", q:"Varón de 35 años con antecedente de prostatitis, acude a consulta por presentar disuria, polaquiuria y dolor suprapúbico. Examen: puntos renoureterales medios (+). Examen de orina: leucocitos 20 por campo y urocultivo en proceso. ¿Cuál es el tratamiento de elección?", o:["Nitrofurantoína","Amoxicilina","Levofloxacino","Cotrimoxazol","Cefuroxima"], c:2, e:"En la prostatitis, las fluoroquinolonas (levofloxacino) son de elección por su excelente penetración al tejido prostático, a diferencia de la nitrofurantoína que no alcanza concentraciones tisulares adecuadas."},
{ex:"2018-A", n:70, area:"GIN", tema:"Lesión intraepitelial de alto grado", q:"Paciente de 36 años, acude por sangrado vaginal postcoital recurrente y flujo vaginal mal oliente que no cede a tratamiento; en el Papanicolaou se encuentra lesión intraepitelial escamosa de alto grado. ¿Cuál es el siguiente paso en el proceso diagnóstico?", o:["Tomografía","Histerectomía","Laparoscopía","Colposcopía","Conización"], c:3, e:"Ante una citología con lesión intraepitelial de alto grado, el siguiente paso es la colposcopía con biopsia dirigida, antes de decidir un tratamiento definitivo como la conización."},
{ex:"2018-A", n:71, area:"MED", tema:"Factores de riesgo cáncer gástrico", q:"¿Cuál es el factor de riesgo para cáncer gástrico?", o:["Helicobacter pylori","Gastritis aguda","Diarrea crónica","Giardia lamblia","Esofagitis crónica"], c:0, e:"La infección crónica por Helicobacter pylori es el principal factor de riesgo modificable para el desarrollo de cáncer gástrico, a través de la secuencia gastritis crónica-atrofia-metaplasia-displasia-cáncer."},
{ex:"2018-A", n:72, area:"MED", tema:"Meningitis tuberculosa", q:"En el estudio del líquido cefalorraquídeo se encuentra: recuento de leucocitos 50 células por µl, a predominio de linfocitos, con hipoglucorraquia e hiperproteinorraquia. ¿Cuál es el agente etiológico más probable?", o:["Virus de la inmunodeficiencia humana","Cryptococcus neoformans","Micobacterium tuberculosae","Diplococcus pneumoniae","Naegleria fowleri"], c:2, e:"El perfil de LCR con pleocitosis linfocitaria moderada, hipoglucorraquia marcada e hiperproteinorraquia elevada es característico de la meningitis tuberculosa, a diferencia de la bacteriana (predominio PMN) o viral (proteínas más discretas)."},
{ex:"2018-A", n:73, area:"CIR", tema:"Conjuntivitis bacteriana", q:"Adolescente de 15 años, desde hace 48 horas presenta secreción ocular derecha que se acompaña de dolor, escozor intenso y fotofobia. Se diagnostica conjuntivitis bacteriana. ¿Cuál es el germen más frecuente?", o:["Streptococcus pneumoniae","Staphylococcus aureus","Chlamydia trachomatis","Mycoplasma pneumoniae","Klebsiella sp"], c:1, e:"Staphylococcus aureus es el agente más frecuente de conjuntivitis bacteriana aguda en adolescentes y adultos, mientras que S. pneumoniae y H. influenzae predominan en niños pequeños."},
{ex:"2018-A", n:74, area:"CIR", tema:"Hemorroides internas", q:"Mujer de 56 años, con estreñimiento crónico y tumoración sangrante que protruye por margen anal al defecar, que se reduce manualmente. Examen anal: tumoración blanda suprapectínea que protruye en el cuadrante anterior derecho. Se diagnostica hemorroides internas. ¿A qué grado corresponde?", o:["II","IV","V","I","III"], c:4, e:"El prolapso hemorroidal que ocurre con la defecación y requiere reducción manual (pero no es espontáneamente irreductible) corresponde al grado III, a diferencia del grado IV que permanece prolapsado de forma permanente."},
{ex:"2018-A", n:75, area:"PED", tema:"Epistaxis anterior", q:"¿Cuál es el manejo inicial de la epistaxis anterior en niños?", o:["Uso de hemostáticos locales","Cauterización del punto de sangrado","Compresión digital por 5 minutos","Taponamiento nasal anterior","Uso de adrenalina local"], c:2, e:"El manejo inicial de la epistaxis anterior es la compresión digital continua de las alas nasales por al menos 5-10 minutos, con el paciente sentado e inclinado hacia adelante, antes de recurrir a medidas más invasivas."},
{ex:"2018-A", n:76, area:"MED", tema:"Gota inducida por tiazidas", q:"Varón de 70 años, hipertenso, diabético, hipertiroideo, llevado a emergencia por presentar dolor en primer dedo de pie derecho. Examen: aumento de volumen en primera articulación metatarso falángica derecha. ¿Cuál es el fármaco asociado a este efecto adverso?", o:["Insulina","Metformina","Enalapril","Hidroclorotiazida","Levotiroxina"], c:3, e:"La monoartritis aguda del primer ortejo (podagra) es típica de una crisis de gota; los diuréticos tiazídicos como la hidroclorotiazida reducen la excreción renal de ácido úrico y precipitan estas crisis."},
{ex:"2018-A", n:77, area:"PED", tema:"Anemia falciforme", q:"Escolar de 6 años procedente de Ica, es traído a emergencia por presentar dolor óseo generalizado, ictericia y palidez marcada. Examen: hepatoesplenomegalia, extremidades normales. Laboratorio: hemoglobina 6 g/dl, BT 12 mg/dl, BD 2 mg/dl, eritrocitos en semiluna. ¿Cuál es el diagnóstico?", o:["Dengue","Brucelosis","Paludismo","Anemia falciforme","Leptospirosis"], c:3, e:"La presencia de eritrocitos en forma de semiluna (drepanocitos) junto con anemia hemolítica, dolor óseo (crisis vasooclusiva) y hepatoesplenomegalia confirma la anemia falciforme."},
{ex:"2018-A", n:78, area:"CIR", tema:"Síndrome compartimental - causa", q:"En un politraumatizado con fracturas en miembros superiores, ¿cuál es la causa más frecuente de síndrome compartimental?", o:["Alteración del drenaje linfático","Isquemia de los tejidos blandos","Contractura muscular","Fracturas óseas","Edema muscular"], c:4, e:"El edema muscular postraumático dentro de un compartimento osteofascial inextensible es la causa más frecuente de aumento de la presión intracompartimental y del síndrome compartimental agudo."},
{ex:"2018-A", n:79, area:"SP", tema:"Vigilancia epidemiológica de IIH", q:"¿Cuál es el procedimiento ideal de vigilancia epidemiológica de las infecciones intrahospitalarias en el establecimiento de salud, según la Directiva Sanitaria de Supervisión?", o:["Activa","Centinela","Pasiva","De eventos","Mixta"], c:4, e:"La vigilancia mixta, que combina la búsqueda activa de casos con la notificación pasiva del personal de salud, es el procedimiento ideal para la vigilancia de infecciones intrahospitalarias según la normativa vigente."},
{ex:"2018-A", n:80, area:"SP", tema:"Muerte materna directa", q:"Granmultigesta a término, sin control prenatal, acude por contracciones uterinas. Al examen: LCF 140x', contracciones uterinas 3 en 10 min con dilatación completa, luego del parto fallece por presentar atonía uterina. ¿Cuál es el tipo de muerte materna?", o:["Tardía","Indirecta","Extrema","Temprana","Directa"], c:4, e:"La muerte materna directa resulta de complicaciones obstétricas propias del embarazo, parto o puerperio, como la hemorragia por atonía uterina; se diferencia de la indirecta, causada por una patología preexistente agravada por la gestación."},
{ex:"2018-A", n:81, area:"PED", tema:"Convulsión febril simple", q:"Lactante de 12 meses, sin antecedentes patológicos, traído por su madre a emergencia por presentar bruscamente fiebre alta, convulsiones tónico-clónicas generalizadas con duración de 10 minutos y recuperación de la conciencia. ¿Cuál es el diagnóstico probable?", o:["Síncope febril","Convulsión febril compleja","Estado epiléptico","Mioclonías generalizadas","Convulsión febril simple"], c:4, e:"Una convulsión generalizada, única, de menos de 15 minutos de duración, con recuperación completa de la conciencia, en un niño entre 6 meses y 5 años con fiebre, define la convulsión febril simple, de buen pronóstico."},
{ex:"2018-A", n:82, area:"CB", tema:"Mediadores broncodilatadores", q:"¿Qué sustancia química produce broncodilatación?", o:["Prostaglandina E2","Prostaglandina D2","Factor activador de plaquetas","Histamina","Leucotrieno D4"], c:0, e:"A diferencia de la prostaglandina D2, la histamina y los leucotrienos (broncoconstrictores), la prostaglandina E2 tiene un efecto broncodilatador sobre el músculo liso de la vía aérea."},
{ex:"2018-A", n:83, area:"MED", tema:"Derrame pleural trasudado", q:"¿En cuál de las siguientes enfermedades se encuentra derrame pleural de tipo trasudado?", o:["Mesotelioma","Mixedema","Hernia diafragmática","Granulomatosis de Wegener","Lupus eritematoso sistémico"], c:1, e:"El mixedema (hipotiroidismo severo) puede producir derrame pleural de tipo trasudado por acumulación de mucopolisacáridos y alteración de la permeabilidad capilar, mientras que las demás opciones producen exudados."},
{ex:"2018-A", n:84, area:"GIN", tema:"Desprendimiento prematuro de placenta", q:"Gestante a término, acude por presentar contracciones uterinas esporádicas, hace una hora dolor intenso en abdomen. Examen: PA 90/60 mmHg, FC 90x', FR 18x', AU 34 cm, LCF 110x', abdomen: hipersensibilidad e incremento del tono uterino y evidencia sangrado vaginal. ¿Cuál es el diagnóstico más probable?", o:["Desprendimiento prematuro de placenta","Ruptura del seno marginal","Ruptura uterina","Vasa previa","Placenta previa"], c:0, e:"El dolor abdominal intenso de inicio súbito, con hipertonía uterina, sufrimiento fetal y sangrado vaginal, es el cuadro clásico del desprendimiento prematuro de placenta normoinserta."},
{ex:"2018-A", n:85, area:"GIN", tema:"Mastitis puerperal", q:"¿Cuál es el microorganismo que se aísla con mayor frecuencia en la mastitis puerperal?", o:["Enterococcus faecalis","Klebsiella pneumoniae","Estreptococcus sp","Staphylococcus aureus","Proteus mirabilis"], c:3, e:"Staphylococcus aureus, proveniente de la piel materna o de la orofaringe del lactante, es el agente causal más frecuente de la mastitis puerperal."},
{ex:"2018-A", n:86, area:"MED", tema:"Depresión mayor", q:"Varón de 48 años, desde hace un mes presenta cambios de carácter, irritabilidad y dificultad para realizar actividades en el trabajo, que se acentúan durante las mañanas. Esposa refiere que está más callado, demuestra poco interés por las actividades del hogar, melancolía, adinamia y pérdida de peso. ¿Cuál es el diagnóstico más probable?", o:["Trastorno distímico","Fobia social","Obsesivo compulsivo","Depresión mayor","Ansiedad generalizada"], c:3, e:"Anhedonia, ánimo depresivo con empeoramiento matutino, adinamia y pérdida de peso durante al menos un mes configuran un episodio de depresión mayor, más intenso y agudo que la distimia."},
{ex:"2018-A", n:87, area:"CIR", tema:"Estenosis biliar postoperatoria", q:"En la estenosis del conducto colédoco como complicación post operatoria, ¿cuál es la intervención quirúrgica indicada?", o:["Coledocoduodenostomía","Colocación de dren de Kher","Hepatoyeyunostomía en Y de Roux","Colédoco anastomosis término-terminal","Dilatación del colédoco vía endoscópica"], c:2, e:"La hepatoyeyunostomía en Y de Roux es la técnica de elección para la reconstrucción de estenosis biliares postoperatorias complejas, al proporcionar una derivación biliodigestiva amplia y duradera."},
{ex:"2018-A", n:88, area:"CB", tema:"Hematología - leucocitos", q:"¿Qué elementos formes de la sangre (leucocitos) son más abundantes por microlitro en adultos?", o:["Eosinófilos","Basófilos","Monocitos","Neutrófilos","Linfocitos"], c:3, e:"Los neutrófilos representan la mayor proporción de leucocitos circulantes en el adulto sano (60-70% del recuento diferencial), seguidos por los linfocitos."},
{ex:"2018-A", n:89, area:"CIR", tema:"Anestesia epidural - complicación", q:"Varón de 36 años, con quemadura de 2° grado en el 45% de la superficie corporal, 3er grado en miembros inferiores; se indica fasciotomía. En el preoperatorio se administran 2 L de solución salina EV. ¿Cuál es la complicación más frecuente de la anestesia epidural?", o:["Cardiopatía isquémica","Relajación muscular","Hipotensión arterial","Parálisis respiratoria","Cefalea intensa"], c:2, e:"El bloqueo simpático producido por la anestesia epidural genera vasodilatación, siendo la hipotensión arterial la complicación más frecuente, especialmente relevante en un paciente quemado con riesgo de hipovolemia."},
{ex:"2018-A", n:90, area:"CB", tema:"Bioquímica de la lactosa", q:"Infante de 3 años, con diarrea crónica, que se exacerba luego de la ingesta de leche. Sospecha de deficiencia de lactasa. ¿En qué monosacáridos se fragmenta la lactosa?", o:["Fructosa y galactosa","Sacarosa y manosa","Manosa y fructosa","Galactosa y glucosa","Glucosa y celulosa"], c:3, e:"La lactasa hidroliza la lactosa (disacárido) en sus dos monosacáridos constituyentes: glucosa y galactosa, que en su deficiencia permanecen sin absorber generando diarrea osmótica."},
{ex:"2018-A", n:91, area:"PED", tema:"Taquipnea transitoria del RN", q:"Varón, recién nacido a término por cesárea electiva, APGAR 9 al minuto. A las dos horas presenta dificultad respiratoria, taquipnea, quejido espiratorio y retracciones. Rx de tórax: hiperexpansión, horizontalización costal, infiltrados perihiliares y diafragma plano. ¿Cuál es el diagnóstico?", o:["Membrana hialina","Taquipnea transitoria","Neumonía aspirativa","Síndrome de aspiración meconial","Displasia broncopulmonar"], c:1, e:"El nacimiento por cesárea electiva sin trabajo de parto, con dificultad respiratoria leve-moderada de inicio precoz y el patrón radiológico de hiperinsuflación con infiltrados perihiliares, son característicos de la taquipnea transitoria del RN, por reabsorción tardía del líquido pulmonar."},
{ex:"2018-A", n:92, area:"MED", tema:"Carcinoma papilar de tiroides", q:"Mujer de 50 años, desde hace 6 años con aumento progresivo del volumen en el cuello, sin dolor. Hace un año se agrega disfagia y cansancio. Examen: tiroides aumentada de tamaño, nódulo de 3x3 cm, superficie irregular y consistencia dura. Laboratorio: TSH elevado; ecografía: nódulo sólido hipoecogénico, contornos irregulares con microcalcificaciones centrales, más alto que ancho. ¿Cuál es el diagnóstico más probable?", o:["Enfermedad de Plummer","Tiroiditis de Hashimoto","Bocio endémico","Carcinoma papilar","Carcinoma folicular"], c:3, e:"Un nódulo duro, irregular, hipoecogénico, con microcalcificaciones y morfología 'más alto que ancho' son signos ecográficos de alta sospecha de malignidad; el carcinoma papilar es el tipo histológico más frecuente de cáncer de tiroides."},
{ex:"2018-A", n:93, area:"CIR", tema:"Medición de presión compartimental", q:"Ante la duda diagnóstica de síndrome compartimental en miembro superior, ¿cuál es el método más utilizado para la medición de la presión intracompartimental?", o:["Monitoreo de pulsos arteriales distales","Método de Stryker","Ecodoppler seriado","Catéter con mecha o hendidura","Espectroscopía"], c:1, e:"El dispositivo de Stryker es el método más utilizado en la práctica clínica para medir directamente la presión intracompartimental, ante la duda diagnóstica de síndrome compartimental; el catéter de mecha es otra alternativa válida pero menos difundida."},
{ex:"2018-A", n:94, area:"SP", tema:"Vacuna fiebre amarilla", q:"En la prevención de la fiebre amarilla, ¿a cuántos días de la vacuna se logra la inmunidad?", o:["5","20","30","15","10"], c:4, e:"La vacuna contra la fiebre amarilla confiere inmunidad protectora a partir de los 10 días de su aplicación, por lo que se recomienda administrarla con esa anticipación antes de viajar a zonas endémicas."},
{ex:"2018-A", n:95, area:"GIN", tema:"Atrofia endometrial", q:"Paciente de 59 años, acude por presentar desde hace 8 semanas sangrado vaginal escaso, color marrón oscuro. FUR hace 9 años, sin antecedentes patológicos, ni ingesta de fármacos. Examen ginecológico normal. ¿Cuál es la causa más frecuente?", o:["Pólipo cervical","Atrofia endometrial","Hiperplasia endometrial","Carúncula uretral","Cáncer endometrial"], c:1, e:"La atrofia endometrial es la causa más frecuente de sangrado uterino anormal en la posmenopausia, aunque siempre debe descartarse cáncer de endometrio mediante ecografía transvaginal dada la edad de la paciente."},
{ex:"2018-A", n:96, area:"CB", tema:"Farmacología anticonvulsivantes", q:"¿Cuál es el anticonvulsivante que actúa inhibiendo los canales de sodio?", o:["Fenitoína","Pregabalina","Gabapentina","Etosuximida","Vigabatrina"], c:0, e:"La fenitoína actúa bloqueando los canales de sodio dependientes de voltaje, estabilizando la membrana neuronal; la etosuximida actúa sobre canales de calcio tipo T y la vigabatrina inhibe el catabolismo del GABA."},
{ex:"2018-A", n:97, area:"PED", tema:"Ictericia neonatal - bilirrubina", q:"La bilirrubina se encuentra en varias formas en la sangre; en la ictericia del recién nacido, la aparición de orina colúrica se debe a...", o:["circulación de bilirrubina libre","ligazón a proteína Z y ligandina","unión de la bilirrubina a la albúmina","catabolismo del Hem","degradación de hemoglobina eritrocitaria"], c:2, e:"Clave oficial: unión de la bilirrubina a la albúmina. Nota de revisión: fisiológicamente la orina colúrica se explica mejor por la bilirrubina conjugada (hidrosoluble) filtrada por el riñón; esta pregunta amerita revisión adicional por la ambigüedad de las opciones ofrecidas."},
{ex:"2018-A", n:98, area:"PED", tema:"Depresión en adolescentes", q:"¿Qué caracteriza al síndrome depresivo en adolescentes?", o:["Hiperfagia","Insomnio","Alucinaciones","Verborrea","Irritabilidad"], c:4, e:"A diferencia del adulto, en el adolescente la depresión suele manifestarse con irritabilidad marcada y conducta oposicionista más que con el ánimo triste clásico."},
{ex:"2018-A", n:99, area:"SP", tema:"MAIS-BFC", q:"En el Modelo de Atención Integral en Salud basado en Familia y Comunidad, el eje de los determinantes de la salud corresponde a:", o:["Las actividades sectoriales","La dimensión técnico operativa","El eje de las necesidades de salud","La dimensión política","Los prestadores de servicios"], c:3, e:"En el MAIS-BFC, la dimensión política es el eje que articula los determinantes sociales de la salud dentro del modelo de atención integral, al enmarcar las decisiones de política pública que los afectan."},
{ex:"2018-A", n:100, area:"GIN", tema:"Amenorrea hipotalámica", q:"¿Cuál es el tipo de amenorrea en una mujer con diagnóstico de anorexia nervosa?", o:["Idiopática","Autoinmunitaria","Ambiental","Hipotalámica","Iatrogénica"], c:3, e:"La restricción calórica severa y el bajo peso de la anorexia nerviosa suprimen la secreción hipotalámica de GnRH, generando una amenorrea hipotalámica funcional (hipogonadismo hipogonadotrópico)."},

];
